package org.example.matrix.models;

import io.wcm.testing.mock.aem.junit5.AemContext;
import io.wcm.testing.mock.aem.junit5.AemContextExtension;
import org.apache.sling.api.resource.Resource;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;

import static org.junit.jupiter.api.Assertions.*;

@ExtendWith(AemContextExtension.class)
class MatrixAgentTest {

    private final AemContext context = new AemContext();

    @BeforeEach
    void setUp() {
        // Create test content
        context.create().resource("/content/agents/neo",
            "name", "Neo",
            "role", "The One",
            "isTheOne", true);
    }

    @Test
    void testMatrixAgent() {
        Resource resource = context.resourceResolver().getResource("/content/agents/neo");
        MatrixAgent agent = resource.adaptTo(MatrixAgent.class);

        assertNotNull(agent, "Agent should not be null");
        assertEquals("Neo", agent.getName());
        assertEquals("The One", agent.getRole());
        assertTrue(agent.canSeeTheMatrix(), "Neo can see the Matrix!");
    }
}
